import Link from 'next/link';

async function getPosts() {
  // In a real app, you'd fetch this from your API
  return [
    { id: 1, title: 'Hello Next.js', content: 'This is my first post.' },
    { id: 2, title: 'Full-Stack Apps', content: 'Generating full-stack apps is fun.' },
  ];
}

export default async function HomePage() {
  const posts = await getPosts();
  return (
    <main className="p-8">
      <h1 className="text-4xl font-bold mb-8">My Blog</h1>
      <div className="space-y-4">
        {posts.map(post => (
          <Link key={post.id} href={`/posts/${post.id}`}>
            <a className="block p-4 border rounded-lg hover:bg-gray-100">
              <h2 className="text-2xl font-semibold">{post.title}</h2>
            </a>
          </Link>
        ))}
      </div>
    </main>
  );
}

async function getPost(id) {
  // Fetch single post
  return { id, title: `Post ${id}`, content: `Content for post ${id}` };
}

export default async function PostPage({ params }) {
  const post = await getPost(params.id);
  return (
    <article className="p-8">
      <h1 className="text-4xl font-bold mb-4">{post.title}</h1>
      <p>{post.content}</p>
    </article>
  );
}

