import { NextResponse } from 'next/server';

export async function GET() {
  // Logic to fetch posts from database
  const posts = [{ id: 1, title: 'API Post' }];
  return NextResponse.json(posts);
}

export async function POST(request) {
  const body = await request.json();
  // Logic to create a new post in the database
  return NextResponse.json({ message: 'Post created', post: body }, { status: 201 });
}

import { NextResponse } from 'next/server';

export async function GET(request, { params }) {
  const { id } = params;
  // Logic to get post by id
  return NextResponse.json({ id, title: `Post ${id}` });
}

export async function PUT(request, { params }) {
  const { id } = params;
  const body = await request.json();
  // Logic to update post
  return NextResponse.json({ message: `Post ${id} updated` });
}

export async function DELETE(request, { params }) {
  const { id } = params;
  // Logic to delete post
  return NextResponse.json({ message: `Post ${id} deleted` });
}

database.schema:
CREATE TABLE users (
  id SERIAL PRIMARY KEY,
  username VARCHAR(50) UNIQUE NOT NULL,
  password_hash VARCHAR(255) NOT NULL,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE posts (
  id SERIAL PRIMARY KEY,
  user_id INTEGER NOT NULL REFERENCES users(id),
  title VARCHAR(255) NOT NULL,
  content TEXT NOT NULL,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE comments (
  id SERIAL PRIMARY KEY,
  post_id INTEGER NOT NULL REFERENCES posts(id),
  user_id INTEGER NOT NULL REFERENCES users(id),
  content TEXT NOT NULL,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);
